import osimport socketimport sysimport jsonfrom tqdm import tqdmfrom Searcher import listener# Планы:# Отправка избранных девайсам не в локальной сети## Сделать порт на телефон## Сделать выбор пользователей, подтверждения выбора# Что такое cheksum:# https://www.geeksforgeeks.org/computer-networks/error-detection-code-checksum/# https://www.geeksforgeeks.org/computer-networks/error-detection-in-computer-networks/# https://elc.github.io/python-security/chapters/04_Checksum.html# https://www.geeksforgeeks.org/python/implementing-checksum-using-python/def read_file(target_file, chunk_size=8192):    with open(target_file, 'rb') as f:        while True:            bytes_read = f.read(chunk_size)            if not bytes_read:                break            yield bytes_readdef send_msg(client, message):    msg_len_bytes = len(message).to_bytes(4, byteorder='big')    client.sendall(msg_len_bytes + message.encode('utf-8'))def choose_file():    print('received_files:')    files = os.listdir('received_files')    for num,file in enumerate(os.listdir('received_files')):        print('-',num,'-',file)    target_file = files[int(input('Введите номер файла для отправки: '))]    print(f'Выбран файл: {target_file}')    return os.path.join('received_files', target_file)def chose_device(devices):    while True:        print('Выберите устройство для отправки:')        for num, device in enumerate(devices, start=1):            print(f"{num}. {device['name']}")        print('Или напишите 0, чтобы обновить список ещё раз')        while True:            try:                choice = int(input("Введите число: "))                if choice == 0:                    devices = listener(5)                else:                    try:                        return devices[choice-1]                    except IndexError:                        print("Пожалуйста, выберите корректное устройство.")            except ValueError:                print("Пожалуйста, введите корректное число.")def main(target_file):    file_name = os.path.basename(target_file)    file_size = os.path.getsize(target_file)    file_info = {'name': file_name, 'size': file_size, 'checksum': "Тут ебля"}    devices = listener(2)    device = chose_device(devices)    # print(devices)    another_user = device    client = socket.socket(socket.AF_INET, socket.SOCK_STREAM)    client.connect((another_user['hostname'], 8080))    send_msg(client, json.dumps(file_info))    with tqdm(total=file_info['size'], unit='B', unit_scale=True, desc=f"Отправка {target_file}") as progress:        for i in read_file(target_file):            progress.update(len(i))            client.sendall(i)            # print(f"Отправлено широковещательное сообщение: {i}")if __name__ == '__main__':    if len(sys.argv) > 1:        windows_file_path = sys.argv[1]        main(windows_file_path)        input("\nНажмите Enter для выхода...")    else:        local_file_path = choose_file()        main(local_file_path)